import { useEffect } from 'react';
import { QueryClientProvider } from '@tanstack/react-query';
import { Toaster } from 'sonner';
import { queryClient } from '@lib/queryClient';
import { ThemeProvider, useTheme, LayoutProvider, AuthProvider, useAuth, NotificationProvider } from '@context';
import AppRoutes from '@/routes';
import '@styles/index.css';


function SessionExpiredListener() {
    const { logout } = useAuth();
    useEffect(() => {
        const handleSessionExpired = (event) => {
            console.warn('Session expired:', event.detail?.message);
            logout();
            window.location.href = '/login?session=expired';
        };
        window.addEventListener('session-expired', handleSessionExpired);
        return () => window.removeEventListener('session-expired', handleSessionExpired);
    }, [logout]);
    return null;
}

function ThemedToaster() {
    const { mode } = useTheme();
    return (
        <Toaster
            theme={mode}
            position="top-right"
            expand={true}
            richColors
            closeButton
            duration={4000}
            toastOptions={{
                className: 'nx-toast',
                style: {
                    fontFamily: 'var(--nx-font-sans)',
                    borderRadius: 'var(--nx-radius-lg)',
                },
            }}
        />
    );
}

function GlobalAppLoader() {
    const { loading } = useAuth();
    const isAuthPage = window.location.pathname.match(/^\/(login|forgot-password|reset-password|set-password)/);

    if (!loading || isAuthPage) return null;

    return (
        <div className="app-loader">
            <div className="app-loader__spinner"></div>
        </div>
    );
}

export default function App() {
    return (
        <QueryClientProvider client={queryClient}>
            <AuthProvider>
                <ThemeProvider>
                    <NotificationProvider>
                        <LayoutProvider>
                            <SessionExpiredListener />
                            <GlobalAppLoader />
                            <AppRoutes />
                            <ThemedToaster />
                        </LayoutProvider>
                    </NotificationProvider>
                </ThemeProvider>
            </AuthProvider>
        </QueryClientProvider>
    );
}

import { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { cn } from '@lib/cn';
import './DataTable.css';

/**
 * A modern, optimized tooltip component that only appears
 * if the content is actually truncated (overflowing).
 */
export function CellTooltip({ content, children, className, maxWidth = 300 }) {
    const [isTruncated, setIsTruncated] = useState(false);
    const [isVisible, setIsVisible] = useState(false);
    const [coords, setCoords] = useState({ x: 0, y: 0 });
    const triggerRef = useRef(null);

    const checkTruncation = () => {
        if (triggerRef.current) {
            const { scrollWidth, clientWidth } = triggerRef.current;
            setIsTruncated(scrollWidth > clientWidth);
        }
    };

    useEffect(() => {
        checkTruncation();
        window.addEventListener('resize', checkTruncation);
        return () => window.removeEventListener('resize', checkTruncation);
    }, [content]);

    const handleMouseEnter = (e) => {
        if (!isTruncated) return;
        const rect = triggerRef.current.getBoundingClientRect();
        setCoords({
            x: rect.left + rect.width / 2,
            y: rect.top - 10
        });
        setIsVisible(true);
    };

    return (
        <div className={cn('dt-cell-tooltip-wrapper', className)}>
            <div
                ref={triggerRef}
                className="dt-cell-truncate"
                onMouseEnter={handleMouseEnter}
                onMouseLeave={() => setIsVisible(false)}
            >
                {children || content}
            </div>

            <AnimatePresence>
                {isVisible && (
                    <motion.div
                        className="dt-tooltip-popup"
                        initial={{ opacity: 0, y: 5, scale: 0.95 }}
                        animate={{ opacity: 1, y: 0, scale: 1 }}
                        exit={{ opacity: 0, y: 5, scale: 0.95 }}
                        transition={{ duration: 0.15 }}
                        style={{
                            left: coords.x,
                            top: coords.y,
                            maxWidth
                        }}
                    >
                        {content}
                        <div className="dt-tooltip-arrow" />
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
}

export default CellTooltip;

import { Search, X, RefreshCw, Columns3, Download, Printer, FileSpreadsheet } from "lucide-react";
import { useReactToPrint } from "react-to-print";
import { saveAs } from "file-saver";
import Papa from "papaparse";
import { SearchBar } from "@components/common";
import { Select } from "@components/ui";

export default function TableToolbar({
  data = [],
  columns = [],
  visibleColumns = [],
  onColumnToggle,
  fileName = "data",
  printRef,
  // Search Props
  search,
  onSearchChange,
  searchPlaceholder = "Search...",
  // Refresh & Loading
  onRefresh,
  loading = false,
  // Custom Filters Slot
  filters,
  // Export Handlers
  onExportCSV,
  onExportPDF,
}) {
  const handlePrint = useReactToPrint({
    contentRef: printRef,
    documentTitle: fileName,
  });

  const handleExportCSV = () => {
    if (onExportCSV) return onExportCSV();
    const csv = Papa.unparse(
      data.map((row) => {
        const mapped = {};
        columns.forEach((col) => {
          if (col.key !== "actions" && visibleColumns.includes(col.key)) {
            mapped[col.label] = row[col.key];
          }
        });
        return mapped;
      })
    );
    const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
    saveAs(blob, `${fileName}.csv`);
  };

  const handleExportPDF = () => {
    if (onExportPDF) return onExportPDF();
    const json = JSON.stringify(data, null, 2);
    const blob = new Blob([json], { type: "application/json" });
    saveAs(blob, `${fileName}.json`);
  };

  const columnOptions = columns
    .filter((c) => c.key !== "actions")
    .map((c) => ({ label: c.label, value: c.key }));

  return (
    <div className="table-toolbar">
      <div className="toolbar-left">
        {onSearchChange && (
          <SearchBar
            placeholder={searchPlaceholder}
            value={search || ""}
            onSearch={onSearchChange}
            size="md"
            className="toolbar-search-pro"
            showShortcut={false}
          />
        )}
      </div>

      <div className="toolbar-right">
        {filters && <div className="toolbar-filters">{filters}</div>}

        <div className="toolbar-actions">
          <Select
            options={columnOptions}
            value={visibleColumns}
            multiple
            onChange={(newValues) => {
              const currentSet = new Set(visibleColumns);
              const newSet = new Set(newValues);
              let toggledKey = null;
              for (const key of currentSet) {
                if (!newSet.has(key)) {
                  toggledKey = key;
                  break;
                }
              }
              if (!toggledKey) {
                for (const key of newSet) {
                  if (!currentSet.has(key)) {
                    toggledKey = key;
                    break;
                  }
                }
              }
              if (toggledKey) onColumnToggle(toggledKey);
            }}
            placeholder="Columns"
            icon={Columns3}
            fullWidth={false}
            className="toolbar-column-select"
            renderValue={() => (
              <span className="column-select-value">
                {visibleColumns.length} Columns
              </span>
            )}
          />

          <div className="toolbar-divider" />

          <button
            type="button"
            className="toolbar-btn toolbar-btn--pdf"
            onClick={handleExportPDF}
            title="Export PDF"
          >
            <Download size={18} />
          </button>

          <button
            type="button"
            className="toolbar-btn toolbar-btn--csv"
            onClick={handleExportCSV}
            title="Export CSV"
          >
            <FileSpreadsheet size={18} />
          </button>

          <button
            type="button"
            className="toolbar-btn toolbar-btn--print"
            onClick={handlePrint}
            title="Print Table"
          >
            <Printer size={18} />
          </button>

        </div>
      </div>
    </div>
  );
}

import { useState, useMemo, useCallback, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Bell, CheckCircle2, Clock, Inbox, AlertTriangle, Info, RefreshCw } from 'lucide-react';
import { cn } from '@lib/cn';
import { useNotifications } from '@hooks/useNotifications';
import { formatDistanceToNow } from 'date-fns';
import { Skeleton } from '@components/ui/Skeleton/Skeleton';
import './NotificationDrawer.css';

// Type icon mapping
const TYPE_ICONS = {
    success: { icon: CheckCircle2, className: 'text-success' },
    warning: { icon: AlertTriangle, className: 'text-warning' },
    error: { icon: AlertTriangle, className: 'text-error' },
    info: { icon: Info, className: 'text-info' },
};

// Skeleton loader for notifications
function NotificationSkeleton() {
    return (
        <div className="notification-list">
            {Array.from({ length: 4 }).map((_, i) => (
                <div key={i} className="notification-item">
                    <Skeleton width="36px" height="36px" borderRadius="50%" />
                    <div className="notification-details" style={{ flex: 1 }}>
                        <Skeleton width="70%" height="14px" />
                        <Skeleton width="90%" height="12px" style={{ marginTop: 6 }} />
                        <Skeleton width="60px" height="10px" style={{ marginTop: 6 }} />
                    </div>
                </div>
            ))}
        </div>
    );
}

function NotificationDrawer({ isOpen, onClose }) {
    const [activeTab, setActiveTab] = useState('all');

    // Fetch notifications from real API
    const {
        notifications,
        unreadCount,
        loading,
        fetchNotifications,
        markAsRead,
        markAllAsRead
    } = useNotifications();

    // Fetch notifications when drawer opens or tab changes
    useEffect(() => {
        if (isOpen) {
            fetchNotifications({
                limit: 20,
                unreadOnly: activeTab === 'unread' ? true : undefined
            });
        }
    }, [isOpen, activeTab, fetchNotifications]);

    const handleMarkAllRead = () => markAllAsRead();
    const handleMarkAsRead = (id) => markAsRead(id);

    // Get icon for notification type
    const getTypeIcon = (type) => {
        const config = TYPE_ICONS[type] || TYPE_ICONS.info;
        const IconComponent = config.icon;
        return <IconComponent size={18} className={config.className} />;
    };

    // Format time
    const formatTime = (dateString) => {
        try {
            return formatDistanceToNow(new Date(dateString), { addSuffix: true });
        } catch {
            return 'Recently';
        }
    };

    return (
        <AnimatePresence>
            {isOpen && (
                <>
                    <motion.div
                        className="notification-backdrop"
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={onClose}
                    />
                    <motion.div
                        className="notification-drawer"
                        initial={{ x: '100%' }}
                        animate={{ x: 0 }}
                        exit={{ x: '100%' }}
                        transition={{ type: 'spring', damping: 25, stiffness: 200 }}
                    >
                        <div className="drawer-header">
                            <div className="drawer-title">
                                <Bell size={20} />
                                <h3>Notifications</h3>
                                {unreadCount > 0 && <span className="badge-count">{unreadCount}</span>}
                            </div>
                            <div className="drawer-actions">
                                <button
                                    className="refresh-btn"
                                    onClick={() => fetchNotifications({
                                        limit: 20,
                                        unreadOnly: activeTab === 'unread' ? true : undefined
                                    })}
                                    disabled={loading}
                                    title="Refresh"
                                >
                                    <RefreshCw size={16} className={loading ? 'spinning' : ''} />
                                </button>
                                <button className="close-btn" onClick={onClose}>
                                    <X size={20} />
                                </button>
                            </div>
                        </div>

                        <div className="drawer-tabs">
                            <button
                                className={cn('tab-btn', activeTab === 'all' && 'active')}
                                onClick={() => setActiveTab('all')}
                            >
                                All
                            </button>
                            <button
                                className={cn('tab-btn', activeTab === 'unread' && 'active')}
                                onClick={() => setActiveTab('unread')}
                            >
                                Unread
                            </button>
                            {unreadCount > 0 && (
                                <button
                                    className="mark-read-btn"
                                    onClick={handleMarkAllRead}
                                >
                                    Mark all read
                                </button>
                            )}
                        </div>

                        <div className="drawer-content">
                            {loading ? (
                                <NotificationSkeleton />
                            ) : notifications.length === 0 ? (
                                <div className="empty-notifications">
                                    <div className="empty-icon"><Inbox size={32} /></div>
                                    <p>No {activeTab === 'unread' ? 'unread ' : ''}notifications</p>
                                </div>
                            ) : (
                                <div className="notification-list">
                                    {notifications.map(notification => (
                                        <div
                                            key={notification.id}
                                            className={cn('notification-item', !notification.is_read && 'unread')}
                                            onClick={() => !notification.is_read && handleMarkAsRead(notification.id)}
                                        >
                                            <div className="notification-icon">
                                                {getTypeIcon(notification.type)}
                                            </div>
                                            <div className="notification-details">
                                                <h4>{notification.title}</h4>
                                                <p>{notification.message}</p>
                                                <span className="notification-time">
                                                    {formatTime(notification.created_at)}
                                                </span>
                                            </div>
                                            {!notification.is_read && <div className="unread-dot" />}
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    </motion.div>
                </>
            )}
        </AnimatePresence>
    );
}

export default NotificationDrawer;

import { useState, useCallback, memo, useEffect } from "react";
import { NavLink, useLocation, useNavigate } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import {
  ChevronLeft,
  ChevronDown,
  X,
  LayoutGrid,
  Building2,
  Users,
  Settings,
  Bell,
  LineChart,
  FileText,
  ShieldAlert,
  LogOut,
  CreditCard,
  Briefcase,
  FolderOpen,
  ListChecks,
  Heart,
  Timer,
  Trash2,
  ShieldCheck,
} from "lucide-react";
import { ConfirmModal } from "@components/ui/Modal";
import { cn } from "@lib/cn";
import { slideInFromLeft, collapse, rotate, sidebarItem } from "@lib/motion";
import nexoFull from "@assets/logo/nexo-full.png";
import nexo from "@assets/logo/nexo.png";
import { ROLE_LABELS } from "@constants/roles";
import "./Sidebar.css";

const SidebarLink = memo(function SidebarLink({
  to,
  icon: Icon,
  label,
  isCollapsed,
  badge,
  onClick,
}) {
  return (
    <NavLink
      to={to}
      className={({ isActive }) =>
        cn("ds-sidebar__link", isActive && "ds-sidebar__link--active")
      }
      onClick={onClick}
    >
      <motion.div className="ds-sidebar__link-content" variants={sidebarItem}>
        <span className="ds-sidebar__link-icon">
          <Icon size={20} />
        </span>
        <AnimatePresence mode="wait">
          {!isCollapsed && (
            <motion.span
              className="ds-sidebar__link-label"
              initial={{ opacity: 0, width: 0 }}
              animate={{ opacity: 1, width: "auto" }}
              exit={{ opacity: 0, width: 0 }}
              transition={{ duration: 0.2 }}
            >
              {label}
            </motion.span>
          )}
        </AnimatePresence>
        {badge && !isCollapsed && (
          <span className="ds-sidebar__badge">{badge}</span>
        )}
      </motion.div>
    </NavLink>
  );
});

const SidebarGroup = memo(function SidebarGroup({
  label,
  icon: Icon,
  children,
  isCollapsed,
  defaultOpen = false,
}) {
  const [isOpen, setIsOpen] = useState(defaultOpen);
  const location = useLocation();
  const isChildActive = children?.some?.((child) =>
    location.pathname.startsWith(child.props?.to)
  );

  const handleToggle = useCallback(() => {
    if (!isCollapsed) {
      setIsOpen((prev) => !prev);
    }
  }, [isCollapsed]);

  return (
    <div
      className={cn(
        "ds-sidebar__group",
        isChildActive && "ds-sidebar__group--active"
      )}
    >
      <button
        className="ds-sidebar__group-trigger"
        onClick={handleToggle}
        aria-expanded={isOpen}
      >
        <span className="ds-sidebar__link-icon">
          <Icon size={20} />
        </span>
        {!isCollapsed && (
          <>
            <span className="ds-sidebar__link-label">{label}</span>
            <motion.span
              className="ds-sidebar__group-chevron"
              animate={isOpen ? "expanded" : "collapsed"}
              variants={rotate}
            >
              <ChevronDown size={16} />
            </motion.span>
          </>
        )}
      </button>

      <AnimatePresence>
        {isOpen && !isCollapsed && (
          <motion.div
            className="ds-sidebar__group-content"
            variants={collapse}
            initial="initial"
            animate="animate"
            exit="exit"
          >
            {children}
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
});

function Sidebar({
  role = "super-admin",
  user = { name: "John Doe", email: "john@example.com" },
  onLogout,
  isOpen = false,
  onClose,
}) {
  const navigate = useNavigate();
  const [isCollapsed, setIsCollapsed] = useState(false);
  const [showLogoutModal, setShowLogoutModal] = useState(false);
  const [loggingOut, setLoggingOut] = useState(false);

  useEffect(() => {
    console.log("Sidebar isOpen changed:", isOpen);
    console.log("onClose function:", typeof onClose);
  }, [isOpen, onClose]);

  const toggleSidebar = useCallback(() => {
    setIsCollapsed((prev) => !prev);
  }, []);

  const handleClose = useCallback(() => {
    console.log("Close button clicked");
    if (onClose) {
      console.log("Calling onClose");
      onClose();
    } else {
      console.log("onClose is not defined!");
    }
  }, [onClose]);

  const handleBackdropClick = useCallback(() => {
    console.log("Backdrop clicked");
    if (onClose) {
      console.log("Calling onClose from backdrop");
      onClose();
    }
  }, [onClose]);

  const handleLinkClick = useCallback(() => {
    if (window.innerWidth <= 768 && onClose) {
      console.log("Link clicked on mobile, closing sidebar");
      onClose();
    }
  }, [onClose]);

  const handleLogoutClick = useCallback(() => {
    setShowLogoutModal(true);
  }, []);

  const handleLogoutConfirm = useCallback(() => {
    setLoggingOut(true);
    // onLogout is defined in DashboardLayout as a call to AuthContext.logout()
    onLogout?.()
      .catch((error) => {
        console.error("Logout error:", error);
      })
      .finally(() => {
        setLoggingOut(false);
        setShowLogoutModal(false);
        navigate("/login", { replace: true });
      });
  }, [onLogout, navigate]);

  const superAdminLinks = [
    { to: "/dashboard", icon: LayoutGrid, label: "Dashboard" },
    { to: "/organizations", icon: Building2, label: "Organizations" },
    { to: "/requests", icon: FileText, label: "Requests" },
    { to: "/payments", icon: CreditCard, label: "Payments" },
    { to: "/billing", icon: Briefcase, label: "Plans & Coupons" },
    { to: "/logs", icon: ShieldAlert, label: "System Logs" },
    { to: "/notifications", icon: Bell, label: "Notifications" },
    { to: "/policy", icon: ShieldCheck, label: "Privacy Policy" },
    { to: "/settings", icon: Settings, label: "Settings" },
  ];

  const getLinksForRole = () => {
    return superAdminLinks;
  };

  const links = getLinksForRole();
  const roleLabel = ROLE_LABELS[role] || "User";

  const userDisplayName = user?.full_name || user?.name || user?.email?.split('@')[0] || "User";
  const userInitials = userDisplayName
    .split(" ")
    .filter(Boolean)
    .map((n) => n[0])
    .join("")
    .toUpperCase()
    .slice(0, 2);

  return (
    <>
      <div
        className={cn("ds-sidebar-backdrop", isOpen && "show")}
        onClick={handleBackdropClick}
      />

      <aside
        className={cn(
          "ds-sidebar",
          isCollapsed && "ds-sidebar--collapsed",
          isOpen && "ds-sidebar--open"
        )}
      >
        <div className="ds-sidebar__header">
          <div className="ds-sidebar__logo">
            <AnimatePresence mode="wait">
              {isCollapsed ? (
                <motion.img
                  key="compact"
                  src={nexo}
                  alt="Nexo"
                  className="ds-sidebar__logo-compact"
                  initial={{ opacity: 0, scale: 0.8 }}
                  animate={{ opacity: 1, scale: 1 }}
                  exit={{ opacity: 0, scale: 0.8 }}
                />
              ) : (
                <motion.img
                  key="full"
                  src={nexoFull}
                  alt="Nexo"
                  className="ds-sidebar__logo-full"
                  initial={{ opacity: 0, x: -10 }}
                  animate={{ opacity: 1, x: 0 }}
                  exit={{ opacity: 0, x: -10 }}
                />
              )}
            </AnimatePresence>
          </div>

          <button
            className="ds-sidebar__close"
            onClick={handleClose}
            aria-label="Close sidebar"
          >
            <X size={20} />
          </button>

          <button
            className="ds-sidebar__toggle"
            onClick={toggleSidebar}
            aria-label={isCollapsed ? "Expand sidebar" : "Collapse sidebar"}
          >
            <ChevronLeft size={16} transition={{ duration: 0.3 }} style={{ transform: isCollapsed ? 'rotate(180deg)' : 'none' }} />
          </button>
        </div>

        <nav className="ds-sidebar__nav">
          {links.map((link) => (
            <SidebarLink
              key={link.to}
              to={link.to}
              icon={link.icon}
              label={link.label}
              badge={link.badge}
              isCollapsed={isCollapsed}
              onClick={handleLinkClick}
            />
          ))}
        </nav>

        <div className="ds-sidebar__footer">
          <div className={cn("ds-sidebar__user-card", isCollapsed && "ds-sidebar__user-card--collapsed")}>
            <div className="ds-sidebar__user-details">
              <div className="ds-sidebar__user-avatar">
                {user.avatar ? (
                  <img src={user.avatar} alt={userDisplayName} />
                ) : (
                  <span>{userInitials}</span>
                )}
              </div>
              {!isCollapsed && (
                <motion.div
                  className="ds-sidebar__user-meta"
                  initial={{ opacity: 0, x: -10 }}
                  animate={{ opacity: 1, x: 0 }}
                >
                  <span className="ds-sidebar__user-name">{userDisplayName}</span>
                  <span className="ds-sidebar__user-role">{roleLabel}</span>
                </motion.div>
              )}
            </div>

            {!isCollapsed && (
              <button
                className="ds-sidebar__action-btn logout"
                onClick={handleLogoutClick}
                title="Logout"
              >
                <LogOut size={16} strokeWidth={2.5} />
              </button>
            )}
          </div>
        </div>
      </aside>

      <ConfirmModal
        isOpen={showLogoutModal}
        onClose={() => setShowLogoutModal(false)}
        onConfirm={handleLogoutConfirm}
        title="Account Logout"
        description="Are you sure you want to exit your Super Admin session? You'll need to re-authenticate to regain access to the NEXO dashboard."
        confirmText="Logout Now"
        variant="logout"
        cancelText="Cancel"
        loading={loggingOut}
      />
    </>
  );
}

export default Sidebar;
export { Sidebar, SidebarLink, SidebarGroup };

import React, { forwardRef } from "react";
import { Info, CheckCircle2, AlertTriangle, XCircle, X } from "lucide-react";
import "./Alert.css";

const ICON_MAP = {
  info: Info,
  success: CheckCircle2,
  warning: AlertTriangle,
  error: XCircle,
};

export const AlertContainer = ({ children, className = "" }) => {
  return (
    <div
      className={["ds-alert-container", className].filter(Boolean).join(" ")}
    >
      {children}
    </div>
  );
};

const Alert = forwardRef((props, ref) => {
  const {
    title,
    children,
    variant = "info",
    onDismiss,
    className = "",
    ...rest
  } = props;

  const Icon = ICON_MAP[variant] || Info;

  const componentClasses = ["ds-alert", `ds-alert--${variant}`, className]
    .filter(Boolean)
    .join(" ");

  return (
    <div ref={ref} role="alert" className={componentClasses} {...rest}>
      <div className="ds-alert__icon">
        <Icon size={20} strokeWidth={2.5} />
      </div>

      <div className="ds-alert__body">
        {title && <strong className="ds-alert__title">{title}</strong>}
        <div className="ds-alert__description">{children}</div>
      </div>

