                <svg className="health-gauge__svg" viewBox="0 0 128 128">
                    <circle className="health-gauge__track" cx="64" cy="64" r="56" />
                    <circle 
                        className="health-gauge__progress" 
                        cx="64" cy="64" r="56"
                        style={{ strokeDasharray, strokeDashoffset }}
                    />
