    if (!org) return null;

    const usagePercent = org.max_users ? Math.round((org.users_count / org.max_users) * 100) : 0;

    return (
        <div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.4, delay: 0.1 }}
            className="org-stats-wrapper"
        >
