export default function DisableOrgModal({ isOpen, onClose, orgId, orgName, onSuccess }) {
    const [reason, setReason] = useState('');
    const [loading, setLoading] = useState(false);

    const handleDisable = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            // API CALL MOCK
            await new Promise(resolve => setTimeout(resolve, 800));
            onSuccess?.();
            onClose();
        } finally {
            setLoading(false);
        }
