function OrganizationDetailPage() {
  const { setHeaderProps } = useLayout();
  const {
    org,
    loading,
    modals,
    openModal,
    closeModal,
    handleEnable,
    handleDelete,
    refetch,
    navigate
  } = useOrganizationDetail();

  useEffect(() => {
    if (org) {
      setHeaderProps({
        title: org.name,
        action: null
      });
    }
  }, [setHeaderProps, org]);

  if (loading) return <OrgSkeleton />;

  return (
    <PageContainer>
      <div className="org-detail">

        <OrgHero
          org={org}
          onEnable={handleEnable}
          onDisable={() => openModal('disable')}
          onNotify={() => openModal('notify')}
          onManagePlan={() => openModal('plan')}
          onManageCoupons={() => openModal('coupons')}
        />

        <OrgStats org={org} />

        <div className="org-content-grid">
          <OrgInfo
            org={org}
            onResetPassword={() => openModal('reset')}
          />

          <OrgSidebar
            org={org}
            onResetPassword={() => openModal('reset')}
            onDelete={() => openModal('delete')}
          />
        </div>
      </div>

      <ResetPasswordModal
        isOpen={modals.reset}
        onClose={() => closeModal('reset')}
        orgId={org.id}
        onSuccess={() => refetch()}
      />

      <DisableOrgModal
        isOpen={modals.disable}
        onClose={() => closeModal('disable')}
        orgId={org.id}
        orgName={org.name}
        onSuccess={() => refetch()}
      />

      <ConfirmModal
        isOpen={modals.delete}
        onClose={() => closeModal('delete')}
        onConfirm={handleDelete}
        title="Delete Organization"
        description={`Are you sure you want to delete "${org.name}"? This action cannot be undone.`}
        confirmText="Delete"
        variant="delete"
      />

      <SendNotificationModal
        isOpen={modals.notify}
        onClose={() => closeModal('notify')}
        orgName={org.name}
        orgId={org.id}
      />

      <ManageCouponsModal
        isOpen={modals.coupons}
